class {{nama_class}}:
    """REST API client using stdlib urllib."""
    def __init__(self, base_url='{{base_url}}', timeout={{timeout}}, default_headers=None):
        self.base_url = base_url.rstrip('/')
        self.timeout = timeout
        self.default_headers = default_headers or {}

    def _build_request(self, method, path, data=None, headers=None, params=None):
        url = self.base_url + '/' + path.lstrip('/')
        if params:
            url += '?' + urllib.parse.urlencode(params)
        body = None
        hdrs = dict(self.default_headers)
        hdrs.update(headers or {})
        if data is not None:
            body = json.dumps(data).encode('utf-8')
            hdrs.setdefault('Content-Type', 'application/json')
        req = urllib.request.Request(url, data=body, headers=hdrs, method=method)
        return req

    def _do(self, method, path, data=None, headers=None, params=None):
        req = self._build_request(method, path, data, headers, params)
        with urllib.request.urlopen(req, timeout=self.timeout) as resp:
            body = resp.read().decode('utf-8')
            content_type = resp.headers.get('Content-Type', '')
            if 'json' in content_type:
                return json.loads(body)
            return body

    def get(self, path, **kw):
        return self._do('GET', path, **kw)

    def post(self, path, data=None, **kw):
        return self._do('POST', path, data=data, **kw)

    def put(self, path, data=None, **kw):
        return self._do('PUT', path, data=data, **kw)

    def delete(self, path, **kw):
        return self._do('DELETE', path, **kw)

class {{nama_class}}:
    """Generic API paginator supporting offset and cursor modes."""
    def __init__(self, fetch_func, page_size={{page_size}}):
        self.fetch_func = fetch_func
        self.page_size = page_size

    def paginate_offset(self, url, items_key='results', next_key='next', page_param='page', size_param='per_page'):
        """Offset-based pagination. fetch_func(url) must return dict."""
        page = 1
        while True:
            sep = '&' if '?' in url else '?'
            paged_url = url + sep + page_param + '=' + str(page) + '&' + size_param + '=' + str(self.page_size)
            data = self.fetch_func(paged_url)
            items = data.get(items_key, [])
            if not items:
                break
            yield from items
            if not data.get(next_key):
                break
            page += 1

    def paginate_cursor(self, url, items_key='results', cursor_key='next_cursor', cursor_param='cursor'):
        """Cursor-based pagination."""
        cursor = None
        while True:
            sep = '&' if '?' in url else '?'
            if cursor:
                paged_url = url + sep + cursor_param + '=' + str(cursor)
            else:
                paged_url = url
            data = self.fetch_func(paged_url)
            items = data.get(items_key, [])
            if not items:
                break
            yield from items
            cursor = data.get(cursor_key)
            if not cursor:
                break

class {{nama_class}}:
    """OAuth2 Client Credentials flow with auto token refresh."""
    def __init__(self, token_url, client_id, client_secret, scope=''):
        self.token_url = token_url
        self.client_id = client_id
        self.client_secret = client_secret
        self.scope = scope
        self._token = None
        self._expires_at = 0
        self._buffer = {{buffer_seconds}}

    def _fetch_token(self):
        credentials = base64.b64encode(
            (self.client_id + ':' + self.client_secret).encode()
        ).decode()
        data = urllib.parse.urlencode({
            'grant_type': 'client_credentials',
            'scope': self.scope,
        }).encode()
        req = urllib.request.Request(
            self.token_url,
            data=data,
            headers={
                'Authorization': 'Basic ' + credentials,
                'Content-Type': 'application/x-www-form-urlencoded',
            },
        )
        with urllib.request.urlopen(req) as resp:
            result = json.loads(resp.read())
        self._token = result['access_token']
        self._expires_at = time.time() + result.get('expires_in', 3600)
        return self._token

    def get_token(self):
        if self._token and time.time() < (self._expires_at - self._buffer):
            return self._token
        return self._fetch_token()

    def get_auth_header(self):
        return {'Authorization': 'Bearer ' + self.get_token()}

class {{nama_class}}:
    """Token bucket rate limiter. Thread-safe."""
    def __init__(self, max_tokens={{max_tokens}}, refill_rate={{refill_rate}}):
        self.max_tokens = max_tokens
        self.refill_rate = refill_rate
        self._tokens = float(max_tokens)
        self._last_refill = time.monotonic()
        self._lock = threading.Lock()

    def _refill(self):
        now = time.monotonic()
        elapsed = now - self._last_refill
        self._tokens = min(self.max_tokens, self._tokens + elapsed * self.refill_rate)
        self._last_refill = now

    def acquire(self, blocking=True, timeout=None):
        """Try to acquire a token. Returns True if acquired."""
        deadline = time.monotonic() + (timeout or 0) if timeout else None
        while True:
            with self._lock:
                self._refill()
                if self._tokens >= 1.0:
                    self._tokens -= 1.0
                    return True
                if not blocking:
                    return False
            if deadline and time.monotonic() >= deadline:
                return False
            time.sleep(1.0 / self.refill_rate)

    def wait(self):
        """Block until a token is available."""
        self.acquire(blocking=True)

class {{nama_class}}:
    """Build GraphQL query/mutation strings from Python dicts."""
    def __init__(self):
        self._operation = None
        self._name = ''
        self._variables = {}
        self._fields = []

    def query(self, name=''):
        self._operation = 'query'
        self._name = name
        return self

    def mutation(self, name=''):
        self._operation = 'mutation'
        self._name = name
        return self

    def fields(self, *field_names):
        self._fields.extend(field_names)
        return self

    def variable(self, name, gql_type, value=None):
        self._variables[name] = {'type': gql_type, 'value': value}
        return self

    def build(self):
        var_defs = ', '.join(
            '$' + name + ': ' + spec['type']
            for name, spec in self._variables.items()
        )
        var_part = '(' + var_defs + ')' if var_defs else ''
        name_part = ' ' + self._name if self._name else ''
        fields_str = '\n    '.join(self._fields) if self._fields else '__typename'
        return self._operation + name_part + var_part + ' {\n    ' + fields_str + '\n}'

    def get_variables(self):
        return {name: spec['value'] for name, spec in self._variables.items() if spec['value'] is not None}


def {{nama_fungsi_exec}}(url, query_str, variables=None, headers=None):
    """Execute a GraphQL query via HTTP POST."""
    import urllib.request
    payload = json.dumps({'query': query_str, 'variables': variables or {}}).encode('utf-8')
    hdrs = {'Content-Type': 'application/json'}
    hdrs.update(headers or {})
    req = urllib.request.Request(url, data=payload, headers=hdrs, method='POST')
    with urllib.request.urlopen(req) as resp:
        return json.loads(resp.read())

