def {{nama_decorator}}(token_provider):
    """Decorator: inject Bearer token into request function.
    The wrapped function must accept 'headers' keyword argument.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            headers = dict(kwargs.pop('headers', {}) or {})
            token = token_provider.get_token()
            if token:
                headers['Authorization'] = 'Bearer ' + token
            kwargs['headers'] = headers
            return func(*args, **kwargs)
        return wrapper
    return decorator

class {{nama_class}}:
    """Thread-safe in-memory response cache with TTL."""
    def __init__(self, default_ttl={{default_ttl}}):
        self.default_ttl = default_ttl
        self._cache = {}
        self._lock = threading.Lock()

    def _make_key(self, method, url, params=None):
        key = method.upper() + ':' + url
        if params:
            import urllib.parse
            key += '?' + urllib.parse.urlencode(sorted(params.items()))
        return key

    def get(self, method, url, params=None):
        key = self._make_key(method, url, params)
        with self._lock:
            entry = self._cache.get(key)
            if entry and time.time() < entry['expires_at']:
                return entry['data']
            if entry:
                del self._cache[key]
        return None

    def put(self, method, url, data, params=None, ttl=None):
        key = self._make_key(method, url, params)
        ttl = ttl if ttl is not None else self.default_ttl
        with self._lock:
            self._cache[key] = {
                'data': data,
                'expires_at': time.time() + ttl,
            }

    def clear(self):
        with self._lock:
            self._cache.clear()

    def cleanup(self):
        now = time.time()
        with self._lock:
            expired = [k for k, v in self._cache.items() if now >= v['expires_at']]
            for k in expired:
                del self._cache[k]

class {{nama_class}}:
    """Circuit breaker for HTTP calls. States: CLOSED, OPEN, HALF_OPEN."""
    CLOSED = 'CLOSED'
    OPEN = 'OPEN'
    HALF_OPEN = 'HALF_OPEN'

    def __init__(self, failure_threshold={{failure_threshold}}, recovery_timeout={{recovery_timeout}}):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self._state = self.CLOSED
        self._failure_count = 0
        self._last_failure_time = 0
        self._lock = threading.Lock()

    @property
    def state(self):
        with self._lock:
            if self._state == self.OPEN:
                if time.time() - self._last_failure_time >= self.recovery_timeout:
                    self._state = self.HALF_OPEN
            return self._state

    def call(self, func, *args, **kwargs):
        """Execute func with circuit breaker protection."""
        current = self.state
        if current == self.OPEN:
            raise RuntimeError('Circuit breaker is OPEN')
        try:
            result = func(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise

    def _on_success(self):
        with self._lock:
            self._failure_count = 0
            self._state = self.CLOSED

    def _on_failure(self):
        with self._lock:
            self._failure_count += 1
            self._last_failure_time = time.time()
            if self._failure_count >= self.failure_threshold:
                self._state = self.OPEN
